class Solution(object):
    def shipWithinDays(self, weights, days):
        def can_ship(capacity):
            current_weight = 0
            current_days = 1
            for weight in weights:
                if current_weight + weight > capacity:
                    current_days += 1
                    current_weight = weight
                else:
                    current_weight += weight
            return current_days <= days
        left = max(weights)
        right = sum(weights)
        while left < right:
            mid = (left + right) // 2
            if can_ship(mid):
                right = mid
            else:
                left = mid + 1
        return left
